.card-grid { display: grid; grid-template-columns: 1fr; gap: var(--spacing-md); }
@media (min-width: 640px) { .card-grid { grid-template-columns: repeat(2, 1fr); } }
@media (min-width: 1024px) { .card-grid { grid-template-columns: repeat(3, 1fr); } }

.button { display: inline-flex; align-items: center; padding: var(--spacing-sm) var(--spacing-md); border-radius: var(--radius-md); font-size: var(--font-size-body); border: 2px solid transparent; transition: background-color 200ms; }
.button--primary { background: var(--color-primary); color: var(--color-on-primary); }
.button--secondary { background: transparent; color: var(--color-primary); border-color: var(--color-primary); }
.button--ghost { background: transparent; color: var(--color-text); }
